fn main() -> Void {
    if !has_toon() {
        fx {
            println("yyjson unavailable");
        }
        ret;
    }

    let doc: ToonDoc;
    fx {
        doc = toon_parse_file("events_hard_b.json");
    }
    let root: ToonNode = toon_root(doc);
    let events: ToonNode = toon_key(root, "events");

    let infoCount: Int = 0;
    let warnCount: Int = 0;
    let errorCount: Int = 0;
    let firstErrorIndex: Int = -1;

    loop i in 0..toon_len(events) {
        let event: ToonNode = toon_at(events, i);
        let level: Text = toon_get_text(event, "level");
        let msg: Text = toon_get_text(event, "msg");

        fx {
            println("event ", i, ": ", level, " / ", msg);
        }

        if level == "info" {
            infoCount = infoCount + 1;
        } else if level == "warn" {
            warnCount = warnCount + 1;
        } else if level == "error" {
            errorCount = errorCount + 1;
            if firstErrorIndex == -1 {
                firstErrorIndex = i;
            }
        }

        toon_free(event);
    }

    fx {
        println("info = ", infoCount);
        println("warn = ", warnCount);
        println("error = ", errorCount);
    }

    let dominant: Text = "info";
    if errorCount > infoCount && errorCount > warnCount {
        dominant = "error";
    } else if warnCount > infoCount {
        dominant = "warn";
    }

    fx {
        println("dominant = ", dominant);
    }

    if firstErrorIndex == -1 {
        fx {
            println("first error: none");
        }
    } else {
        fx {
            println("first error at index ", firstErrorIndex);
        }
    }

    toon_close(doc);
    ret;
}
