fn main() -> Void {
    if !has_toon() {
        fx {
            println("yyjson unavailable");
        }
        ret;
    }

    let doc: ToonDoc;
    fx {
        doc = toon_parse_file("ops_hard_c.json");
    }
    let root: ToonNode = toon_root(doc);
    let cap: Int = toon_get_int(root, "cap");
    let ops: ToonNode = toon_key(root, "operations");

    let balance: Int = 0;
    let applied: Int = 0;
    let rejected: Int = 0;

    loop i in 0..toon_len(ops) {
        let op: ToonNode = toon_at(ops, i);
        let kind: Text = toon_get_text(op, "kind");
        let amount: Int = toon_get_int(op, "amount");
        let changed: Bool = false;

        if kind == "deposit" {
            let newBal: Int = balance + amount;
            if newBal > cap {
                balance = cap;
            } else {
                balance = newBal;
            }
            fx {
                println("op ", i, ": deposit ", amount, " -> ", balance);
            }
        } else if kind == "withdraw" {
            if balance >= amount {
                balance = balance - amount;
                fx {
                    println("op ", i, ": withdraw ", amount, " -> ", balance);
                }
            } else {
                fx {
                    println("op ", i, ": withdraw ", amount, " REJECTED (balance ", balance, ")");
                }
            }
        } else if kind == "interest" {
            let interest: Int = balance * amount / 100;
            balance = balance + interest;
            fx {
                println("op ", i, ": interest ", amount, "% -> ", balance);
            }
        }

        if changed {
            applied = applied + 1;
        } else {
            rejected = rejected + 1;
        }
    }

    fx {
        println("final balance = ", balance);
        println("applied = ", applied);
        println("rejected = ", rejected);
    }

    toon_close(doc);
    ret;
}
