fn main() -> Void {
    if !has_toon() {
        fx { println("yyjson unavailable"); }
        ret;
    }

    let doc: ToonDoc = toon_parse_file("expenses_hard_a.json");
    let root: ToonNode = toon_root(doc);
    let expenses: ToonNode = toon_key(root, "expenses");
    let count: Int = toon_len(expenses);

    // First pass: compute sum of amounts
    let sum: Real = 0.0;
    loop i in 0..count {
        let row: ToonNode = toon_at(expenses, i);
        let amount: Int = toon_get_int(row, "amount");
        sum = sum + amount;
        toon_free(row);
    }

    let mean: Real = sum / count;
    let halfMean: Real = mean / 2.0;

    // Second pass: compute deviations, mark outliers, print
    let outlierCount: Int = 0;
    let maxDev: Real = 0.0;

    loop i in 0..count {
        let row: ToonNode = toon_at(expenses, i);
        let name: Text = toon_get_text(row, "name");
        let amount: Int = toon_get_int(row, "amount");

        let dev: Real = abs(mean - amount);
        let isOutlier: Bool = dev > halfMean;

        if isOutlier {
            outlierCount = outlierCount + 1;
        }
        if dev > maxDev {
            maxDev = dev;
        }

        fx {
            println("expense ", i, ": ", name, " / ", amount, " / dev ", dev:0:2, " / ", isOutlier);
        }

        toon_free(row);
    }

    fx {
        println("count = ", count);
        println("mean = ", mean:0:2);
        println("outliers = ", outlierCount);
        println("maxDev = ", maxDev:0:2);
    }

    toon_close(doc);
    ret;
}
